class Solution {
    public int reverseDegree(String s) {
        int sum = 0;
        for (int i = 0; i < s.length(); i++) {
            int reverseAlpha = 26 - (s.charAt(i) - 'a');
            sum += reverseAlpha * (i + 1);
        }
        return sum;
    }
}
```
